```Go [sol1-Go]
func robotWithString(s string) string {
    cnt := make([]int, 26)
    for _, c := range s {
        cnt[c - 'a']++
    }

    stack := []rune{}
    res := []rune{}
    minCharacter := 'a'
    for _, c := range s {
        stack = append(stack, c)
        cnt[c - 'a']--
        for minCharacter != 'z' && cnt[minCharacter - 'a'] == 0 {
            minCharacter++
        }
        for len(stack) > 0 && stack[len(stack) - 1] <= minCharacter {
            res = append(res, stack[len(stack) - 1])
            stack = stack[:len(stack) - 1]
        }
    }

    return string(res)
}
```

```C [sol1-C]
char* robotWithString(char* s) {
    int cnt[26] = {0};
    int len = strlen(s);
    for (int i = 0; i < len; i++) {
        cnt[s[i] - 'a']++;
    }

    char* stack = (char*)malloc(len * sizeof(char));
    int top = 0;
    char* res = (char*)malloc((len + 1) * sizeof(char));
    int pos = 0;
    char minCharacter = 'a';
    for (int i = 0; i < len; i++) {
        stack[top++] = s[i];
        cnt[s[i] - 'a']--;
        while (minCharacter != 'z' && cnt[minCharacter - 'a'] == 0) {
            minCharacter++;
        }
        while (top > 0 && stack[top - 1] <= minCharacter) {
            res[pos++] = stack[--top];
        }
    }

    res[pos] = '\0';
    free(stack);
    return res;
}
```

```JavaScript [sol1-JavaScript]
var robotWithString = function(s) {
    let cnt = new Array(26).fill(0);
    for (let c of s) {
        cnt[c.charCodeAt(0) - 'a'.charCodeAt(0)]++;
    }

    let stack = [];
    let res = [];
    let minCharacter = 'a';
    for (let c of s) {
        stack.push(c);
        cnt[c.charCodeAt(0) - 'a'.charCodeAt(0)]--;
        while (minCharacter !== 'z' && cnt[minCharacter.charCodeAt(0) - 'a'.charCodeAt(0)] === 0) {
            minCharacter = String.fromCharCode(minCharacter.charCodeAt(0) + 1);
        }
        while (stack.length > 0 && stack[stack.length - 1] <= minCharacter) {
            res.push(stack.pop());
        }
    }

    return res.join('');
};
```

